use std::sync::atomic::{AtomicI64, Ordering};
use std::sync::Mutex;

struct SensorStats {
    count: AtomicI64,
    sum: AtomicI64,
}

impl SensorStats {
    fn new() -> Self {
        SensorStats {
            count: AtomicI64::new(0),
            sum: AtomicI64::new(0),
        }
    }

    fn record_reading(&self, value: i64) {
        self.count.fetch_add(1, Ordering::SeqCst);
        self.sum.fetch_add(value, Ordering::SeqCst);
    }

    fn get_mean(&self) -> Option<f64> {
        let count = self.count.load(Ordering::SeqCst);
        if count == 0 {
            return None;
        }
        let sum = self.sum.load(Ordering::SeqCst);
        Some(sum as f64 / count as f64)
    }

    fn get_current_state(&self) -> (i64, i64) {
        (self.count.load(Ordering::SeqCst), self.sum.load(Ordering::SeqCst))
    }
}

struct DataStreamer {
    stats: Mutex<SensorStats>,
}

impl DataStreamer {
    fn new() -> Self {
        DataStreamer { stats: Mutex::new(SensorStats::new()) }
    }

    fn process_data(&self, data_points: &[i64]) {
        let mut stats = self.stats.lock().unwrap();
        for &point in data_points {
            stats.record_reading(point);
        }
    }

    fn calculate_statistics(&self) -> Option<f64> {
        let stats = self.stats.lock().unwrap();
        stats.get_mean()
    }
}

fn main() {
    let streamer = DataStreamer::new();
    println!("Starting data simulation...");

    let batch1 = vec![10, 20, 30];
    streamer.process_data(&batch1);
    if let Some(mean) = streamer.calculate_statistics() {
        println!("After Batch 1: Mean is {:.2}", mean);
    }

    let batch2 = vec![5, 15];
    streamer.process_data(&batch2);
    if let Some(mean) = streamer.calculate_statistics() {
        println!("After Batch 2: Mean is {:.2}", mean);
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct ChatRoom {
    id: String,
    user_list: Arc<Mutex<HashMap<String, u32>>>,
}

impl ChatRoom {
    fn new(room_id: String) -> Self {
        ChatRoom {
            id: room_id,
            user_list: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn add_user(&self, username: String) -> Result<(), String> {
        let mut users = self.user_list.lock().unwrap();
        if users.contains_key(&username) {
            return Err(format!("User {} already in room {}", username, self.id));
        }
        users.insert(username, 1);
        Ok(())
    }

    fn broadcast_message(&self, message: &str) -> Result<usize, String> {
        let users = self.user_list.lock().unwrap();
        if users.is_empty() {
            return Err(format!("Cannot broadcast, room {} has no connected users.", self.id));
        }
        println!("[Broadcast in {}] {}", self.id, message);
        Ok(users.len())
    }
}

struct ChatServer {
    rooms: Mutex<HashMap<String, Arc<ChatRoom>>>,
}

impl ChatServer {
    fn new() -> Self {
        ChatServer { rooms: Mutex::new(HashMap::new()) }
    }

    fn get_or_create_room(&self, room_id: &str) -> Arc<ChatRoom> {
        let mut rooms = self.rooms.lock().unwrap();
        if let Some(room) = rooms.get(room_id).cloned() {
            return room;
        }
        let new_room = Arc::new(ChatRoom::new(String::from(room_id)));
        rooms.insert(String::from(room_id), new_room.clone());
        new_room
    }
}

fn main() {
